const B2B_PARISHES = [
  'Saint Patrick Parish',
  'Saint Peter Parish',
  'Saint Paul Parish',
  'Immaculate Conception',
  'Saint Mary Parish',
  'Saint Joseph Parish',
  'Our Lady of the Assumption',
  'Sacred Heart',
]

async function seed() {
  console.log(`Seeding ${parishes.length} real MA Catholic parishes...`)
  let inserted = 0, skipped = 0, errors = 0

  for (const parish of parishes) {
    // Check if already exists
    const { data: existing } = await supabase
      .from('parishes')
      .select('id')
      .eq('name', parish.name)
      .eq('city', parish.city)
      .single()

    if (existing) {
      skipped++
      continue
    }

    const isB2B = B2B_PARISHES.some(b => parish.name.includes(b))

    const { error } = await supabase.from('parishes').insert({
      name: parish.name,
      address: parish.address,
      city: parish.city,
      state: parish.state,
      zip: parish.zip || null,
      phone: parish.phone || null,
      website: parish.website || null,
      diocese: parish.diocese,
      latitude: parish.latitude,
      longitude: parish.longitude,
      is_official: isB2B,
    })

    if (error) {
      console.error(`❌ Error inserting ${parish.name}: ${error.message}`)
      errors++
    } else {
      console.log(`✓ ${parish.name}, ${parish.city}`)
      inserted++
    }
  }

  console.log(`\n✅ Done!`)
  console.log(`   Inserted: ${inserted}`)
  console.log(`   Skipped (already existed): ${skipped}`)
  console.log(`   Errors: ${errors}`)
}

seed().catch(console.error)